// 1. SETTINGS
const targetName = $('Webhook').first().json.query.space_name; // Example of a "fuzzy" input
const fuzzinessThreshold = 3;    // Maximum number of allowed typos/edits

// 2. HELPER FUNCTION: Levenshtein Distance (Calculates edit distance between strings)
function getEditDistance(a, b) {
  if (a.length === 0) return b.length;
  if (b.length === 0) return a.length;

  const matrix = [];

  // increment along the first column of each row
  for (let i = 0; i <= b.length; i++) {
    matrix[i] = [i];
  }

  // increment each column in the first row
  for (let j = 0; j <= a.length; j++) {
    matrix[0][j] = j;
  }

  // Fill in the rest of the matrix
  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1, // substitution
          Math.min(
            matrix[i][j - 1] + 1,   // insertion
            matrix[i - 1][j] + 1    // deletion
          )
        );
      }
    }
  }

  return matrix[b.length][a.length];
}

// 3. MAIN LOGIC
const items = $input.all();
let bestMatch = {
  id: null,
  name: null,
  distance: 100 // Start with a high distance
};

// Normalize target for comparison
const normalizedTarget = targetName.toLowerCase().trim();

for (const item of items) {
  const spaces = item.json.spaces;

  if (spaces && Array.isArray(spaces)) {
    for (const space of spaces) {
      if (!space.name) continue;

      const currentSpaceName = space.name.toLowerCase().trim();

      // Calculate distance
      const distance = getEditDistance(normalizedTarget, currentSpaceName);

      // Check if this is the best match so far
      if (distance < bestMatch.distance) {
        bestMatch = {
          id: space.id,
          name: space.name,
          distance: distance
        };
      }
    }
  }
}

// 4. VALIDATE RESULT
// Only return the ID if the match is within the allowed threshold
const isMatchFound = bestMatch.distance <= fuzzinessThreshold;

return [
  {
    json: {
      search_term: targetName,
      matched_name: isMatchFound ? bestMatch.name : null,
      space_id: isMatchFound ? bestMatch.id : null,
      match_quality: isMatchFound ? `Found with ${bestMatch.distance} edits` : "No match found",
      found: isMatchFound
    }
  }
];

