// Helper function to convert seconds (float) to HH:MM:SS,mmm
function formatTime(totalSeconds) {
    if (totalSeconds === undefined || totalSeconds === null) return "00:00:00,000";

    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = Math.floor(totalSeconds % 60);
    const milliseconds = Math.floor((totalSeconds % 1) * 1000);

    const h = hours.toString().padStart(2, '0');
    const m = minutes.toString().padStart(2, '0');
    const s = seconds.toString().padStart(2, '0');
    const ms = milliseconds.toString().padStart(3, '0');

    // Returns format HH:MM:SS,mmm
    return `${h}:${m}:${s},${ms}`;
}

const results = [];

// Loop through all incoming items
for (const item of $input.all()) {
    const data = item.json;

    // 1. Initialize the new structure with retained ID and Name
    const output = {
        id: data.id || "",
        name: data.name || "",
        transcript: []
    };

    const segments = data.segments || [];
    const allWords = data.words || [];

    // 2. Process each segment and add to the transcript list
    for (const segment of segments) {
        const sentenceObj = {
            sentence: segment.text.trim(),
            start: formatTime(segment.start),
            end: formatTime(segment.end),
            words: []
        };

        // Find words belonging to this segment
        let segmentWords = [];
        if (segment.words && segment.words.length > 0) {
            segmentWords = segment.words;
        } else {
            // Fallback: filter words by time if they aren't nested
            segmentWords = allWords.filter(w => 
                w.start >= segment.start - 0.05 && w.end <= segment.end + 0.05
            );
        }

        // Map words to the desired format
        sentenceObj.words = segmentWords.map(w => ({
            text: w.word.trim(),
            start: formatTime(w.start),
            end: formatTime(w.end)
        }));

        output.transcript.push(sentenceObj);
    }

    results.push({ json: output });
}

return results;

const TARGET_FIELD_NAME = 'Video Type';
