  if (!Array.isArray(task.custom_fields)) continue;

  const field = task.custom_fields.find(
    f => f.name === TARGET_FIELD_NAME
  );

  if (!field || !field.type_config || !Array.isArray(field.type_config.options)) {
    continue;
  }

  const targetOption = field.type_config.options.find(
    opt => opt.label === TARGET_VALUE_LABEL
