    output.push(item);
  }
}

return output;

// ----------------CONFIGURATION----------------
const TIMEBASE = 30; 
const START_FRAME_BUFFER = 5;
const END_FRAME_BUFFER = 3;

function timeToFrameInteger(timeString, timebase) {
    if (!timeString) return 0;
    let parts = timeString.split(':');
    if (parts.length === 2) parts.unshift("00");
    else if (parts.length === 1) parts.unshift("00", "00");

    const ss_ms = parts[2].split(',');   
    const h = parseInt(parts[0]);
    const m = parseInt(parts[1]);
    const s = parseInt(ss_ms[0]);
    const ms = parseInt(ss_ms[1]) || 0;

    const totalSeconds = (h * 3600) + (m * 60) + s;
    return (totalSeconds * timebase) + Math.round((ms / 1000) * timebase); 
}

function framesToEDLTimecode(totalFrames, timebase) {
    const h = Math.floor(totalFrames / (timebase * 3600)).toString().padStart(2, '0');
    const m = Math.floor((totalFrames % (timebase * 3600)) / (timebase * 60)).toString().padStart(2, '0');
    const s = Math.floor((totalFrames % (timebase * 60)) / timebase).toString().padStart(2, '0');
    const f = Math.floor(totalFrames % timebase).toString().padStart(2, '0');
    return `${h}:${m}:${s}:${f}`;
}

