const outputItems = [];

for (const item of $input.all()) {
  const rawName = item.json.name || '';
  const rawContent = item.json.text_content || ''; 

  // --- 1. Extract Drive Folder Link ---
  let driveLink = '';
  let folderId = '';

  // REGEX UPDATED:
  // (?:video\s*)?footage  -> Matches "footage" or "video footage"
  // [\s\S]*?              -> Matches ANY character (including newlines) lazily
  // (https?:\/\/drive\.google\.com\/[^\s\u00a0]+) -> The URL
  const footageRegex = /(?:video\s*)?footage[\s\S]*?(https?:\/\/drive\.google\.com\/[^\s\u00a0]+)/i;
  const match = rawContent.match(footageRegex);

  if (match && match[1]) {
    // Clean the captured URL (remove trailing spaces or characters)
    let potentialLink = match[1].trim();

    // VALIDATION: Ensure it's a folder link
    if (potentialLink.includes('/folders/') || potentialLink.includes('id=')) {
      driveLink = potentialLink;

      // Extract Folder ID
      const idMatch = potentialLink.match(/\/folders\/([a-zA-Z0-9-_]+)|id=([a-zA-Z0-9-_]+)/);
      if (idMatch) {
        folderId = idMatch[1] || idMatch[2];
      }
    }
  }

  // --- 2. Clean the Text Content (script) ---
  let cleanedScript = rawContent;

  // 1a. Remove specific lines like "footage Folder: https://..." 
  // and "XML file link: https://..."
  // This now handles multiline matches
  const lineCleanupRegex = /(?:xml|footage)[\s\S]*?https?:\/\/drive\.google\.com\/[^\s\u00a0]+/gi;
  cleanedScript = cleanedScript.replace(lineCleanupRegex, '');

  // 1b. Remove any remaining URLs (like the Google Drive File placeholders)
  const urlRegex = /(https?:\/\/[^\s]+|www\.[^\s]+)/g;
  cleanedScript = cleanedScript.replace(urlRegex, '').trim();

  // 1c. Remove emoticons/emojis
  const emojiRegex = /(\u00a9|\u00ae|[\u2000-\u3300]|\ud83c[\ud000-\udfff]|\ud83d[\ud000-\udfff]|\ud83e[\ud000-\udfff])/g;
  cleanedScript = cleanedScript.replace(emojiRegex, '').trim();

  // 1d. Remove brackets content (e.g., "(Show monica from the show friends)")
  const bracketRegex = /[\(\[].*?[\)\]]/g;
  cleanedScript = cleanedScript.replace(bracketRegex, '').trim();

  // 1e. Final cleanup of whitespace and special characters
  cleanedScript = cleanedScript.replace(/[\n\t\r]+/g, ' '); 
  // Remove the "FileGoogle Drive File" text often left by ClickUp/Drive icons
  cleanedScript = cleanedScript.replace(/FileGoogle Drive File/gi, '');
  cleanedScript = cleanedScript.replace(/\s{2,}/g, ' ').trim(); 

  // --- 3. Clean the Name Field ---
  let cleanedName = rawName; 

  // --- 4. Create Output Fields ---
  outputItems.push({
    json: {
      script: cleanedScript, 
      name: cleanedName,
      footage_link: driveLink,
      id: folderId 
    }
  });
}

return outputItems;

