    const startFrame = timeToFrameInteger(match.words[0].start, TIMEBASE) - START_FRAME_BUFFER;
    const endFrame = timeToFrameInteger(match.words[match.words.length - 1].end, TIMEBASE) + END_FRAME_BUFFER;
    const duration = Math.max(0, endFrame - startFrame);

    return {
        fileName: match.name || "Unknown_Source",
        sourceStart: Math.max(0, startFrame),
        duration: duration,
        index: index
    };
}).filter(e => e !== null);

// 2. IDENTIFY UNIQUE FILES
const uniqueFiles = [...new Set(timelineEvents.map(e => e.fileName))];

const allTracks = [];

// 3. BUILD TRACKS
uniqueFiles.forEach((targetFileName, i) => {
    const videoChildren = [];
    const audioChildren = [];

    timelineEvents.forEach(event => {
        const isOwner = (event.fileName === targetFileName);
        const duration = event.duration;

        if (isOwner) {
            // Video Clip
            const videoClip = {
                "OTIO_SCHEMA": "Clip.2",
                "metadata": {
                    "Resolve_OTIO": {}
                },
                "name": event.fileName,
                "source_range": {
                    "OTIO_SCHEMA": "TimeRange.1",
                    "start_time": { 
                        "OTIO_SCHEMA": "RationalTime.1", 
                        "rate": TIMEBASE, 
                        "value": event.sourceStart 
                    },
                    "duration": { 
                        "OTIO_SCHEMA": "RationalTime.1", 
                        "rate": TIMEBASE, 
                        "value": duration 
                    }
                },
                "effects": INCLUDE_RESOLVE_EFFECTS ? createVideoEffects() : [],
                "markers": [],
                "enabled": true,
                "media_references": {
                    "DEFAULT_MEDIA": {
                        "OTIO_SCHEMA": "ExternalReference.1",
                        "metadata": {},
                        "name": event.fileName,
                        "available_range": null,
                        "available_image_bounds": null,
                        "target_url": event.fileName
                    }
                },
                "active_media_reference_key": "DEFAULT_MEDIA"
            };

            // Audio Clip
            const audioClip = {
                "OTIO_SCHEMA": "Clip.2",
                "metadata": {
                    "Resolve_OTIO": {
                        "Channels": [
                            {
                                "Source Channel ID": 0,
                                "Source Track ID": 0
                            },
                            {
                                "Source Channel ID": 1,
                                "Source Track ID": 0
                            }
                        ]
                    }
                },
                "name": event.fileName,
                "source_range": {
                    "OTIO_SCHEMA": "TimeRange.1",
                    "start_time": { 
                        "OTIO_SCHEMA": "RationalTime.1", 
                        "rate": TIMEBASE, 
                        "value": event.sourceStart 
                    },
                    "duration": { 
                        "OTIO_SCHEMA": "RationalTime.1", 
                        "rate": TIMEBASE, 
                        "value": duration 
                    }
                },
                "effects": INCLUDE_RESOLVE_EFFECTS ? createAudioEffects() : [],
                "markers": [],
                "enabled": true,
                "media_references": {
                    "DEFAULT_MEDIA": {
                        "OTIO_SCHEMA": "ExternalReference.1",
                        "metadata": {},
                        "name": event.fileName,
                        "available_range": null,
                        "available_image_bounds": null,
                        "target_url": event.fileName
                    }
                },
                "active_media_reference_key": "DEFAULT_MEDIA"
            };

            videoChildren.push(videoClip);
            audioChildren.push(audioClip);
        } else {
            // Gap
            const gap = {
                "OTIO_SCHEMA": "Gap.1",
                "metadata": {},
                "name": "",
                "source_range": {
                    "OTIO_SCHEMA": "TimeRange.1",
                    "duration": { 
                        "OTIO_SCHEMA": "RationalTime.1", 
                        "rate": TIMEBASE, 
                        "value": duration 
                    },
                    "start_time": { 
                        "OTIO_SCHEMA": "RationalTime.1", 
                        "rate": TIMEBASE, 
                        "value": 0 
                    }
                },
                "effects": [],
                "markers": [],
                "enabled": true
            };
            videoChildren.push(JSON.parse(JSON.stringify(gap)));
            audioChildren.push(JSON.parse(JSON.stringify(gap)));
        }
    });

    // Add Video Track
    allTracks.push({
        "OTIO_SCHEMA": "Track.1",
        "metadata": {
            "Resolve_OTIO": {
                "Locked": false
            }
        },
        "name": `V: ${targetFileName}`,
        "source_range": null,
        "effects": [],
        "markers": [],
        "enabled": true,
        "children": videoChildren,
        "kind": "Video"
    });

    // Add Audio Track
    allTracks.push({
        "OTIO_SCHEMA": "Track.1",
        "metadata": {
            "Resolve_OTIO": {
                "Audio Type": "Stereo",
                "Locked": false,
                "SoloOn": false
            }
        },
        "name": `A: ${targetFileName}`,
        "source_range": null,
        "effects": [],
        "markers": [],
        "enabled": true,
        "children": audioChildren,
        "kind": "Audio"
    });
});

// 4. WRAP IT UP
const otioJson = {
    "OTIO_SCHEMA": "Timeline.1",
    "metadata": {
        "Resolve_OTIO": {
            "Resolve OTIO Meta Version": "1.0"
        }
    },
    "name": sequenceName,
    "global_start_time": { 
        "OTIO_SCHEMA": "RationalTime.1", 
        "rate": TIMEBASE, 
        "value": 0.0
    },
    "tracks": {
        "OTIO_SCHEMA": "Stack.1",
        "metadata": {},
        "name": "",
        "source_range": null,
        "effects": [],
        "markers": [],
        "enabled": true,
        "children": allTracks
    }
};

return { otio_json: otioJson, file_name: sequenceName + ".otio" };

const otioObj = $input.first().json.otio_json;   // your XML string
const otioString = JSON.stringify(otioObj, null, 2);
const otioBuffer = Buffer.from(otioString, "utf-8");
const otioBase64 = otioBuffer.toString("base64");

return [
  {
    json: {},
    binary: {
      data: {
        data: otioBase64,
        fileName: $input.first().json.file_name,
        mimeType: "text/plain"
      }
    }
  }
];
